mapper.update:
UPDATE comment_ai_result
   SET status = 'FAILED', error_message = #{errorMessage}, completed_at = NOW()
 WHERE comment_id = #{commentId} AND task_type = #{taskType}

mapper.select:
SELECT cc.id AS post_id, LEFT(cc.content, 50) AS title, '댓글' AS post_category, cc.status AS post_status, cc.is_anonymous AS anonymous, cc.user_id AS author_id, u.name AS author_name, ar.result_json, ar.model, ar.attempt_count, ar.status AS ai_status, cc.created_at, ar.completed_at FROM comment_ai_result ar JOIN community_comment cc ON ar.comment_id = cc.id LEFT JOIN users u ON cc.user_id = u.id WHERE ar.task_type = 'MODERATION'
AND cc.status = #{status}
AND JSON_EXTRACT(ar.result_json, '$.toxic') = #{toxic}
ORDER BY ar.completed_at DESC, cc.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
  FROM comment_ai_result ar
  JOIN community_comment cc ON ar.comment_id = cc.id
 WHERE ar.task_type = 'MODERATION'

   AND cc.status = #{status}


   AND JSON_EXTRACT(ar.result_json, '$.toxic') = #{toxic}
